import { Hono } from 'hono';
import { getSubscriptions, calculateGrowthRate, generateForecast } from '../services/billing';

const app = new Hono();

app.get('/billing-forecast', async (c) => {
  try {
    // Fetch current subscriptions
    const subscriptions = await getSubscriptions();

    // Calculate historical growth rate
    const growthRate = calculateGrowthRate(subscriptions);

    // Generate 3-month billing forecast
    const forecast = generateForecast(subscriptions, growthRate, 3);

    return c.json(forecast);
  } catch (error) {
    console.error('Error generating billing forecast:', error);
    return c.status(500).json({ error: 'Internal Server Error' });
  }
});

export default app;

import { Subscription } from '../models/subscription';

// Mock data for demonstration purposes
const subscriptionsData: Subscription[] = [
  { id: 1, amount: 50, startDate: new Date('2023-01-01') },
  { id: 2, amount: 75, startDate: new Date('2023-04-01') },
];

export async function getSubscriptions(): Promise<Subscription[]> {
  // Simulate fetching subscriptions from a database
  return new Promise((resolve) => {
    setTimeout(() => resolve(subscriptionsData), 100);
  });
}

export function calculateGrowthRate(subscriptions: Subscription[]): number {
  const totalAmount = subscriptions.reduce((acc, sub) => acc + sub.amount, 0);
  const startDate = Math.min(...subscriptions.map(sub => sub.startDate.getTime()));
  const endDate = new Date().getTime();

  return ((totalAmount / (endDate - startDate)) * 12 * 3) / 100; // Annual growth rate
}

export function generateForecast(subscriptions: Subscription[], growthRate: number, months: number): { month: string, forecastedAmount: number }[] {
  const forecast = [];
  const currentDate = new Date();

  for (let i = 1; i <= months; i++) {
    const nextMonth = new Date(currentDate.getFullYear(), currentDate.getMonth() + i, 1);
    const forecastedAmount = subscriptions.reduce((acc, sub) => acc + sub.amount * (1 + growthRate / 100), 0);
    forecast.push({ month: nextMonth.toISOString().split('T')[0], forecastedAmount });
  }

  return forecast;
}

export interface Subscription {
  id: number;
  amount: number;
  startDate: Date;
}

